// MARK: - IoT Device Client

class IoTDeviceClient {
    
    private let httpClient: HTTPClient
    private let deviceBaseURL: String
    
    init(deviceIP: String, port: Int = 80, useHTTPS: Bool = false) {
        self.httpClient = HTTPClient.shared
        let scheme = useHTTPS ? "https" : "http"
        self.deviceBaseURL = "\(scheme)://\(deviceIP):\(port)"
    }
    
    /// Discover device info
    func getDeviceInfo() async throws -> DeviceInfo {
        let response = try await httpClient.get(
            url: "\(deviceBaseURL)/api/info",
            responseType: DeviceInfo.self
        )
        return response.data
    }
    
    /// Get device status
    func getStatus() async throws -> DeviceStatus {
        let response = try await httpClient.get(
            url: "\(deviceBaseURL)/api/status",
            responseType: DeviceStatus.self
        )
        return response.data
    }
    
    /// Send command to device
    func sendCommand(_ command: DeviceCommand) async throws -> CommandResponse {
        let response = try await httpClient.post(
            url: "\(deviceBaseURL)/api/command",
            body: command,
            responseType: CommandResponse.self
        )
        return response.data
    }
    
    /// Toggle device on/off
    func toggle(on: Bool) async throws -> CommandResponse {
        let command = DeviceCommand(action: on ? "on" : "off", parameters: nil)
        return try await sendCommand(command)
    }
    
    /// Update device settings
    func updateSettings(_ settings: DeviceSettings) async throws -> CommandResponse {
        let response = try await httpClient.put(
            url: "\(deviceBaseURL)/api/settings",
            body: settings,
            responseType: CommandResponse.self
        )
        return response.data
    }
    
    /// Check device reachability with a simple ping
    func ping() async -> Bool {
        do {
            let _ = try await httpClient.requestRaw(
                url: "\(deviceBaseURL)/api/ping",
                method: .GET
            )
            return true
        } catch {
            return false
        }
    }
}

// MARK: - Cloud API Client

class CloudAPIClient {
    
    private let httpClient: HTTPClient
    private let baseURL: String
    
    init(baseURL: String = "https://api.example.com") {
        self.httpClient = HTTPClient.shared
        self.baseURL = baseURL
    }
    
    /// Authenticate user
    func login(email: String, password: String) async throws -> AuthResponse {
        let loginRequest = LoginRequest(email: email, password: password)
        let response = try await httpClient.post(
            url: "\(baseURL)/v1/auth/login",
            body: loginRequest,
            responseType: AuthResponse.self
        )
        // Store token for subsequent requests
        httpClient.authToken = response.data.accessToken
        return response.data
    }
    
    /// Register a new device with cloud
    func registerDevice(_ registration: DeviceRegistration) async throws -> RegisteredDevice {
        let response = try await httpClient.post(
            url: "\(baseURL)/v1/devices",
            body: registration,
            responseType: RegisteredDevice.self
        )
        return response.data
    }
    
    /// Get list of registered devices
    func getDevices() async throws -> [RegisteredDevice] {
        let response = try await httpClient.get(
            url: "\(baseURL)/v1/devices",
            responseType: [RegisteredDevice].self
        )
        return response.data
    }
    
    /// Get device telemetry from cloud
    func getDeviceTelemetry(deviceId: String) async throws -> DeviceTelemetry {
        let response = try await httpClient.get(
            url: "\(baseURL)/v1/devices/\(deviceId)/telemetry",
            responseType: DeviceTelemetry.self
        )
        return response.data
    }
    
    /// Send OTA update command via cloud
    func triggerOTAUpdate(deviceId: String, firmwareVersion: String) async throws -> CommandResponse {
        let body = OTAUpdateRequest(firmwareVersion: firmwareVersion)
        let response = try await httpClient.post(
            url: "\(baseURL)/v1/devices/\(deviceId)/ota",
            body: body,
            responseType: CommandResponse.self
        )
        return response.data
    }
    
    /// Delete a registered device
    func deleteDevice(deviceId: String) async throws {
        let _ = try await httpClient.requestRaw(
            url: "\(baseURL)/v1/devices/\(deviceId)",
            method: .DELETE
        )
    }
}

// MARK: - Device Discovery Service

class DeviceDiscoveryService {
    
    /// Scan local network for IoT devices on a given subnet
    func scanSubnet(
        subnet: String = "192.168.1",
        port: Int = 80,
        range: ClosedRange<Int> = 1...254
    ) async -> [DiscoveredDevice] {
        var discoveredDevices: [DiscoveredDevice] = []
        
        await withTaskGroup(of: DiscoveredDevice?.self) { group in
            for i in range {
                let ip = "\(subnet).\(i)"
                group.addTask {
                    let client = IoTDeviceClient(deviceIP: ip, port: port)
                    let reachable = await client.ping()
                    if reachable {
                        do {
                            let info = try await client.getDeviceInfo()
                            return DiscoveredDevice(
                                ipAddress: ip,
                                port: port,
                                info: info
                            )
                        } catch {
                            // Device responded to ping but not to info endpoint
                            return DiscoveredDevice(
                                ipAddress: ip,
                                port: port,
                                info: nil
                            )
                        }
                    }
                    return nil
                }
            }
            
            for await result in group {
                if let device = result {
                    discoveredDevices.append(device)
                }
            }
        }
        
        return discoveredDevices
    }
}

