// MARK: - Usage Example

func exampleUsage() async {
    // --- Cloud API Usage ---
    let cloudAPI = CloudAPIClient()
    
    do {
        // Login
        let auth = try await cloudAPI.login(email: "user@example.com", password: "password123")
        print("Logged in. Token: \(auth.accessToken)")
        
        // Get registered devices
        let devices = try await cloudAPI.getDevices()
        print("Found \(devices.count) registered devices")
        
        // Get telemetry
        if let firstDevice = devices.first {
            let telemetry = try await cloudAPI.getDeviceTelemetry(deviceId: firstDevice.id)
            print("Telemetry: \(telemetry.metrics)")
        }
    } catch {
        print("Cloud API error: \(error.localizedDescription)")
    }
    
    // --- Local Device Discovery ---
    let discovery = DeviceDiscoveryService()
    let discoveredDevices = await discovery.scanSubnet(subnet: "192.168.1", port: 80, range: 1...20)
    print("Discovered \(discoveredDevices.count) local devices")
    
    // --- Local Device Communication ---
    let localDevice = IoTDeviceClient(deviceIP: "192.168.1.100", port: 80, useHTTPS: false)
    
    do {
        // Check if device is reachable
        let reachable = await localDevice.ping()
        print("Device reachable: \(reachable)")
        
        if reachable {
            // Get device info
            let info = try await localDevice.getDeviceInfo()
            print("Device: \(info.name) (\(info.model))")
            
            // Get status
            let status = try await localDevice.getStatus()
            print("Power state: \(status.powerState)")
            
            // Toggle device on
            let toggleResult = try await localDevice.toggle(on: true)
            print("Toggle result: \(toggleResult.success)")
            
            // Send custom command
            let command = DeviceCommand(
                action: "set_brightness",
                parameters: ["level": "75"]
            )
            let cmdResult = try await localDevice.sendCommand(command)
            print("Command result: \(cmdResult.success)")
            
            // Update settings
            let settings = DeviceSettings(
                name: "Living Room Light",
                timezone: "America/New_York",
                autoUpdate: true,
                reportingInterval: 60,
                customSettings: nil
            )
            let settingsResult = try await localDevice.updateSettings(settings)
            print("Settings update: \(settingsResult.success)")
        }
    } catch {
        print("Local device error: \(error.localizedDescription)")
    }
    
    // --- HTTPS Local Device (self-signed cert) ---
    let secureLocalDevice = IoTDeviceClient(
        deviceIP: "192.168.1.200",
        port: 443,
        useHTTPS: true
    )
    
    do {
        let info = try await secureLocalDevice.getDeviceInfo()
        print("Secure local device: \(info.name)")
    } catch {
        print("Secure local device error: \(error.localizedDescription)")
    }
    
    // --- Raw request for non-standard endpoints ---
    let httpClient = HTTPClient.shared
    do {
        let response = try await httpClient.requestRaw(
            url: "http://192.168.1.100/firmware/version",
            method: .GET,
            headers: ["Accept": "text/plain"]
        )
        if let versionString = String(data: response.data, encoding: .utf8) {
            print("Firmware version: \(versionString)")
        }
    } catch {
        print("Raw request error: \(error.localizedDescription)")
    }
}